import Foundation

let questions7: [QuizQuestion] = [
QuizQuestion(id:431,question:"O que Paulo chama de 'o maior dos pecados' em 1 Timóteo 1:15?",options:["O adultério","'Cristo Jesus veio ao mundo para salvar os pecadores","A idolatria","A mentira"],correctIndex:1,explanation:"Paulo em 1 Tm 1:15 se chama o 'principal dos pecadores' — não humildade falsa, mas reconhecimento genuíno de que perseguiu a Igreja e que a graça o alcançou mesmo assim.",reference:"1 Timóteo 1:15-16",category:.geral,propheticMeaning:"Paulo como exemplo da graça para os 'maiores pecadores' revela que o evangelho não tem fundo — se alcançou o perseguidor da Igreja, pode alcançar qualquer um."),
QuizQuestion(id:432,question:"Qual é a promessa de Mateus 5:3 (primeira bem-aventurança)?",options:["'Bem-aventurados os ricos'","'Bem-aventurados os pobres de espírito","'Bem-aventurados os fortes'","'Bem-aventurados os sábios'"],correctIndex:1,explanation:"A primeira bem-aventurança (Mt 5:3): 'pobres de espírito' são os que reconhecem sua bancarrota espiritual e dependência total de Deus — a eles pertence o Reino.",reference:"Mateus 5:3",category:.geral,propheticMeaning:"'Pobre de espírito' é o oposto do orgulho espiritual do fariseu — é a abertura da mão fechada para receber o dom de Deus. É a postura básica do discípulo."),
QuizQuestion(id:433,question:"Qual é a última das Bem-aventuranças em Mateus 5?",options:["Bem-aventurados os misericordiosos","Bem-aventurados os que fazem as pazes","'Bem-aventurados os perseguidos por causa da justiça","Bem-aventurados os puros de coração"],correctIndex:2,explanation:"A última Bem-aventurança (Mt 5:10-12) promete o reino dos céus aos perseguidos por causa da justiça e de Cristo — o mesmo prêmio da primeira, encerrando o ciclo.",reference:"Mateus 5:10-12",category:.geral,propheticMeaning:"A perseguição pelos discípulos é sinal de que estão do lado certo — 'assim perseguiram os profetas que foram antes de vós' (Mt 5:12). Sofrimento é sinal de fidelidade, não de abandono."),
QuizQuestion(id:434,question:"O que Jesus ensinou sobre a lei em Mateus 5:17?",options:["Vim abolir a lei","'Não penseis que vim revogar a lei ou os profetas","A lei não importa mais","A lei foi substituída por uma nova lei"],correctIndex:1,explanation:"Jesus veio cumprir (pleroō) a lei e os profetas — não abolir mas levar ao cumprimento pleno e definitivo. Ele é a lei personificada.",reference:"Mateus 5:17",category:.geral,propheticMeaning:"Cristo cumprindo a lei significa que ela encontra em Cristo seu propósito, não sua extinção. O crente não está sob a lei como sistema de salvação, mas a lei encontra cumprimento em sua vida pela ação do Espírito."),
QuizQuestion(id:435,question:"O que Paulo ensina sobre humildade em Filipenses 2:3?",options:["Cuide apenas de si mesmo","'Nada façais por contenda ou vanglória, mas por humildade","Humildade é fraqueza","Os líderes não precisam de humildade"],correctIndex:1,explanation:"Fp 2:3-4: a humildade cristã considera os outros superiores e busca os interesses alheios — modelada na kenosis de Cristo (Fp 2:5-8).",reference:"Filipenses 2:3-5",category:.geral,propheticMeaning:"'Considerando os outros superiores' não é auto-aniquilação mas reorientação do ego — em vez de comparar-se para subir, serve para que o outro floresça. É o amor que 'não busca os seus próprios interesses' (1 Co 13:5)."),
QuizQuestion(id:436,question:"Qual é o conselho de Paulo a jovens pastores em 1 Timóteo 4:12?",options:["Espere ter mais experiência","'Ninguém despreze a tua juventude","Obedeça sempre aos anciãos","Não pregue até ter 40 anos"],correctIndex:1,explanation:"Paulo instrui Timóteo a ser exemplo em palavra e conduta — a autoridade do jovem pastor vem do caráter e do exemplo, não apenas da posição.",reference:"1 Timóteo 4:12",category:.geral,propheticMeaning:"A liderança cristã é primeiramente modelagem — Paulo diz 'sede imitadores de mim, assim como eu sou de Cristo' (1 Co 11:1). O pastor que não pode ser imitado não deve ser seguido."),
QuizQuestion(id:437,question:"O que Tiago 1:2-3 ensina sobre as provações?",options:["Fuja das provações","'Tende por motivo de muita alegria... quando cairdes em várias","Provações são punição de Deus","Ore para nunca sofrer provação"],correctIndex:1,explanation:"Tiago 1:2-4: as provações produzem perseverança, a perseverança leva à maturidade — motivo de alegria, não de desespero.",reference:"Tiago 1:2-4",category:.geral,propheticMeaning:"'Motivo de alegria' nas provações não é masoquismo mas visão de longo prazo — Paulo igualmente diz 'gloriamo-nos nas tribulações' (Rm 5:3-4) porque o processo produz esperança."),
QuizQuestion(id:438,question:"O que Pedro ensina sobre os sofrimentos em 1 Pedro 4:13?",options:["Os sofrimentos mostram falta de fé","'Alegrai-vos por serdes participantes dos sofrimentos de Cristo","Sofrimentos são punição","Sofrimentos devem ser evitados"],correctIndex:1,explanation:"1 Pe 4:13: participar dos sofrimentos de Cristo prepara para participar de sua glória — o caminho da cruz ao trono.",reference:"1 Pedro 4:13",category:.geral,propheticMeaning:"Participar dos sofrimentos de Cristo (Fp 3:10) é participar da missão de Cristo — o evangelho sempre custou algo a quem o proclamou, começando com o próprio Jesus."),
QuizQuestion(id:439,question:"O que é o 'ministério da reconciliação' em 2 Coríntios 5:18-19?",options:["Apenas reconciliar pessoas entre si","Após reconciliar-nos com Deus em Cristo","Apenas a obra de Cristo no passado","O ministério exclusivo dos apóstolos"],correctIndex:1,explanation:"2 Co 5:18-20: Deus nos reconciliou e nos deu o ministério da reconciliação — todo crente é embaixador de Cristo proclamando 'reconciliai-vos com Deus.'",reference:"2 Coríntios 5:18-20",category:.geral,propheticMeaning:"O evangelho é sempre missional — quem recebeu a reconciliação é enviado a proclamá-la. A Igreja não é um clube dos reconciliados mas uma missão de reconciliadores."),
QuizQuestion(id:440,question:"Qual é o ensinamento de Jesus sobre o sal e a luz em Mateus 5:13-16?",options:["Os cristãos devem se isolar do mundo","'Vós sois o sal da terra e a luz do mundo'","Os cristãos devem ser invisíveis","A luz deve brilhar apenas na Igreja"],correctIndex:1,explanation:"Mt 5:13-16: sal e luz transformam o que tocam — o discípulo influencia o mundo ao seu redor, não vivendo separado mas diferente.",reference:"Mateus 5:13-16",category:.geral,propheticMeaning:"'A cidade edificada sobre o monte não pode esconder-se' (Mt 5:14) — a vida cristã autêntica é naturalmente visível e inevitavelmente influente. Esconder o sal ou apagar a luz contradiz a própria natureza deles."),
QuizQuestion(id:441,question:"O que é o 'Sermão das Bem-aventuranças' e onde foi pregado?",options:["Um discurso no templo","O início do Sermão do Monte (Mt 5-7)","Um sermão em Jerusalém","Um discurso na sinagoga"],correctIndex:1,explanation:"O Sermão do Monte (Mt 5-7), incluindo as oito Bem-aventuranças, foi pregado numa encosta (Mc e Lc situam numa área plana) perto do Mar da Galileia.",reference:"Mateus 5:1-2",category:.geral,propheticMeaning:"Jesus subindo ao monte para ensinar evoca Moisés subindo ao Sinai para receber a lei — Jesus é o novo Moisés dando a lei do Reino, mas não gravada em pedra e sim em corações pelo Espírito."),
QuizQuestion(id:442,question:"O que é o 'Pai Nosso' e quantas petições tem?",options:["Um hino de adoração com 10 petições","Uma oração modelo de Jesus com 6 petições: santificação do nome","Uma oração de arrependimento","Uma liturgia sacerdotal com 12 elementos"],correctIndex:1,explanation:"O Pai Nosso (Mt 6:9-13) tem seis petições: 1) santificação do nome, 2) vinda do reino, 3) vontade de Deus, 4) pão diário, 5) perdão, 6) livramento do mal.",reference:"Mateus 6:9-13",category:.geral,propheticMeaning:"As três primeiras petições são 'tu-centradas' (Deus) e as três últimas são 'nós-centradas' (necessidades humanas) — estrutura que ensina que a adoração precede e fundamenta a supplicação."),
QuizQuestion(id:443,question:"O que Jesus ensina sobre tesouros em Mateus 6:19-21?",options:["Seja rico para honrar a Deus","'Não acumuleis para vós tesouros na terra... mas acumulai para vós","Tesouros são neutros","Evite qualquer posse"],correctIndex:1,explanation:"Mt 6:19-21: onde investimos nosso coração revela nossas prioridades — tesouros celestiais (investimentos no Reino) orientam o coração para o eterno.",reference:"Mateus 6:19-21",category:.geral,propheticMeaning:"O coração segue o tesouro — não o contrário. A conquista espiritual começa com a decisão de onde investir, pois o afeto segue o investimento. Dar é uma disciplina espiritual que reorienta o coração."),
QuizQuestion(id:444,question:"Qual é a promessa de Mateus 6:33?",options:["'Pedi e recebereis'","'Buscai primeiro o reino de Deus e a sua justiça","'Crede e sereis salvos'","'Andai e fazei discípulos'"],correctIndex:1,explanation:"Mt 6:33: buscar primeiro o reino de Deus tem uma promessa: as necessidades materiais serão supridas por um Pai que já sabe o que precisamos.",reference:"Mateus 6:33",category:.geral,propheticMeaning:"'Buscar primeiro o reino' é a antítese do consumismo e ansiedade — Jesus não condena ter necessidades (Mt 6:32), mas reorienta prioridades: quando o eterno é primeiro, o temporal é cuidado pelo Pai."),
QuizQuestion(id:445,question:"O que Jesus ensina sobre julgamento em Mateus 7:1-2?",options:["Nunca avalie o comportamento alheio","'Não julgueis, para que não sejais julgados","Os líderes podem julgar todos...","Só os perfeitos podem julgar"],correctIndex:1,explanation:"Mt 7:1-5: a proibição é de julgamento hipócrita — ver o cisco no olho alheio antes de remover a viga do próprio. O discernimento é necessário, a hipocrisão é condenada.",reference:"Mateus 7:1-5",category:.geral,propheticMeaning:"O julgamento com que julgamos voltará sobre nós — o cristão que julga outros pelo padrão que ele mesmo não cumpre é um fariseu redivivo. O único padrão seguro é o de Cristo, pelo qual todos nos curvamos."),
QuizQuestion(id:446,question:"O que João 1:1-3 diz sobre a identidade de Jesus antes da encarnação?",options:["Jesus foi criado antes do mundo","'No princípio era o Verbo, e o Verbo estava com Deus","Jesus era um anjo","Jesus nasceu em Belém eternamente"],correctIndex:1,explanation:"João 1:1-3: o Logos (Verbo) existia antes de tudo, estava com Deus, era Deus e criou tudo — afirmação explícita da preexistência e divindade de Cristo.",reference:"João 1:1-3",category:.geral,propheticMeaning:"João 1:1 ecoa Gênesis 1:1 deliberadamente — o mesmo Deus que criou no princípio entrou na criação como Verbo encarnado. A criação e a nova criação têm o mesmo agente: Cristo."),
QuizQuestion(id:447,question:"O que significa 'o Verbo se fez carne' em João 1:14?",options:["A Bíblia foi escrita","A encarnação: o Filho eterno de Deus assumiu natureza humana","Uma metáfora para ensino","A criação do homem"],correctIndex:1,explanation:"João 1:14: 'o Verbo se fez carne e habitou entre nós' (eskēnōsen — 'tabernaculizou') — a encarnação do Filho de Deus é o evento central da história.",reference:"João 1:14",category:.geral,propheticMeaning:"'Habitou entre nós' usa vocabulário do tabernáculo — Deus outrora habitou no tabernáculo entre Israel; agora habita em carne humana entre toda a humanidade. A presença de Deus democratizou-se."),
QuizQuestion(id:448,question:"O que Jesus quis dizer com 'Antes que Abraão existisse, Eu Sou' (João 8:58)?",options:["Que era mais velho que Abraão","Afirmação da preexistência eterna e identidade divina usando o Nome","Que conhecia a história de Abraão","Que era descendente de Abraão"],correctIndex:1,explanation:"Jo 8:58: 'antes que Abraão existisse, Eu Sou' (ego eimi, presente eterno) — Jesus afirmou preexistência eterna e usou o Nome divino de Êxodo 3:14. Os judeus entenderam como blasfêmia.",reference:"João 8:58",category:.geral,propheticMeaning:"'Eu Sou' (ego eimi absoluto) em João é sempre afirmação da divindade de Cristo — a mesma que os fariseus reconheceram como blasfêmia e que os discípulos adoraram como verdade."),
QuizQuestion(id:449,question:"O que Jesus disse sobre si mesmo em João 11:25?",options:["'Sou o caminho'","'Eu sou a ressurreição e a vida","'Sou a videira verdadeira'","'Sou o bom pastor'"],correctIndex:1,explanation:"Jo 11:25-26: diante da morte de Lázaro, Jesus afirmou ser a Ressurreição e a Vida — quem crê nele nunca morrerá na acepção plena.",reference:"João 11:25-26",category:.geral,propheticMeaning:"A declaração 'Eu sou a Ressurreição' imediatamente antes de ressuscitar Lázaro é a mais dramática demonstração de que Jesus não apenas promete ressurreição mas é a fonte ontológica de toda vida."),
QuizQuestion(id:450,question:"O que é a parábola do semeador em Mateus 13?",options:["Sobre agricultura judaica","Quatro tipos de solo/coração que recebem a Palavra: caminho (sem","Sobre o reino de Salomão","Sobre o templo de Herodes"],correctIndex:1,explanation:"A parábola do semeador (Mt 13:3-23) ilustra quatro respostas à Palavra de Deus, com apenas o quarto solo (bom coração) produzindo fruto abundante.",reference:"Mateus 13:3-23",category:.geral,propheticMeaning:"A parábola responde à pergunta: por que o evangelho não converte todos? A responsabilidade é da condição do coração, não do poder da Palavra. O solo bom é o que produz o fruto do Reino."),
QuizQuestion(id:451,question:"Qual é a parábola do joio e do trigo?",options:["Sobre boas e más sementes","O Reino de Deus é como campo onde trigo e joio crescem juntos até a","Sobre agricultura","Sobre dieta kosher"],correctIndex:1,explanation:"Mt 13:24-30,36-43: o campo (mundo) tem trigo (filhos do reino) e joio (filhos do maligno) crescendo juntos até o julgamento final.",reference:"Mateus 13:24-30",category:.geral,propheticMeaning:"A parábola ensina paciência escatológica — não cabe à Igreja 'arrancar' os ímpios do mundo, mas proclamar o evangelho para que mais se tornem trigo antes da colheita final."),
QuizQuestion(id:452,question:"O que é a parábola do filho pródigo e o irmão mais velho?",options:["Sobre herança","O Pai amoroso (Deus) acolhe o filho arrependido (pecadores) enquanto","Sobre hospitalidade","Sobre o trabalho na lavoura"],correctIndex:1,explanation:"Lucas 15:11-32 tem dois atos: o filho pródigo arrependido sendo festejado, e o irmão obediente mas ressentido — ambos perdidos, um longe, outro perto mas com o coração distante.",reference:"Lucas 15:11-32",category:.geral,propheticMeaning:"O irmão mais velho representa os religiosos que obedecem por recompensa, não por amor — tão perdidos quanto o pródigo, mas sem perceber. Jesus convida ambos à mesma graça do Pai."),
QuizQuestion(id:453,question:"O que Jesus ensinou sobre o maior no reino em Mateus 18:3-4?",options:["O mais rico é o maior","'Se não vos converterdes e não vos tornardes como crianças","O mais sábio","O mais obediente às regras"],correctIndex:1,explanation:"Mt 18:3-4: o padrão do reino é invertido — a criança (dependente, sem status, sem orgulho) é o modelo do cidadão do reino e do 'maior.'",reference:"Mateus 18:3-4",category:.geral,propheticMeaning:"A criança sem presunção de direitos nem conquistas a defender é a imagem da fé — receptiva, dependente, sem agenda própria. O reino pertence aos que 'empobreceram de espírito' (Mt 5:3)."),
QuizQuestion(id:454,question:"O que Jesus ensina sobre orar em Lucas 18:1-8 (parábola da viúva)?",options:["Ore poucas vezes","'Sempre orar e não esmorecer'","Deus responde apenas à primeira oração","A oração não precisa de persistência"],correctIndex:1,explanation:"A parábola da viúva e o juiz injusto (Lc 18:1-8) ensina que se uma viúva vence um juiz injusto por persistência, quanto mais o Pai justo ouvirá seus filhos.",reference:"Lucas 18:1-8",category:.geral,propheticMeaning:"A questão final é: 'quando o Filho do Homem vier, achará fé na terra?' (Lc 18:8) — a oração persistente é a expressão visível da fé ativa que aguarda a segunda vinda."),
QuizQuestion(id:455,question:"Qual é o milagre da multiplicação dos pães?",options:["Jesus comprou pães para todos...","Jesus multiplicou 5 pães e 2 peixes para alimentar 5.000 homens (além","Jesus ensinou as pessoas a compartilhar","Jesus transformou pedras em pão"],correctIndex:1,explanation:"Mc 6:35-44: Jesus tomou 5 pães e 2 peixes, abençoou e deu aos discípulos — sobrou mais do que havia começado. Único milagre nos quatro Evangelhos.",reference:"Marcos 6:41-44",category:.geral,propheticMeaning:"Jesus alimentando a multidão no deserto ecoa Moisés e o maná — ele é o novo Moisés, o verdadeiro Pão do céu (Jo 6:35). Os 12 cestos restantes apontam para a abundância do reino: há suficiente para todos."),
QuizQuestion(id:456,question:"O que é o episódio de Jesus andando sobre as águas?",options:["Uma metáfora apenas","Jesus andou literalmente sobre o Mar da Galileia à noite","Um sonho dos discípulos","Jesus nadou até o barco"],correctIndex:1,explanation:"Mt 14:25-31: Jesus andou sobre o mar e chamou Pedro que começou a andar mas afundou por dúvida. Jesus o salvou e disse 'por que duvidaste?'",reference:"Mateus 14:25-31",category:.geral,propheticMeaning:"Pedro andando sobre a água enquanto olhava para Jesus, afundando quando olhou para as ondas — perfeita ilustração da fé: o objeto da fé (Cristo) sustenta; o foco nas circunstâncias afunda."),
QuizQuestion(id:457,question:"O que foi a cura dos dez leprosos em Lucas 17?",options:["Jesus curou dez leprosos e todos voltaram agradecer","Jesus curou dez leprosos","Nove leprosos foram curados","Os dez voltaram meses depois"],correctIndex:1,explanation:"Lc 17:11-19: apenas o samaritano voltou para agradecer. Jesus disse: 'não foram dez limpos? onde estão os outros nove?' — e ao samaritano: 'a tua fé te salvou.'",reference:"Lucas 17:15-19",category:.geral,propheticMeaning:"O único grato foi o estranho (samaritano) — os nove israelitas receberam cura física mas apenas um recebeu salvação completa. A gratidão é sinal do coração transformado pela graça."),
QuizQuestion(id:458,question:"O que foi a 'Entrada Triunfal' de Jesus em Jerusalém?",options:["Jesus entrou em segredo","Jesus entrou em Jerusalém montado num jumento","Jesus entrou a cavalo","Jesus foi carregado pela multidão"],correctIndex:1,explanation:"Mt 21:1-11: Jesus entrou em Jerusalém montado num jumento (cumprindo Zc 9:9), aclamado com palmas e gritos de 'Hosana ao Filho de Davi!'",reference:"Mateus 21:1-11; Zacarias 9:9",category:.geral,propheticMeaning:"O jumento (animal de paz, não de guerra) e o título 'Filho de Davi' (Messias) anunciam o tipo de reino que Jesus traz — paz, não revolução armada — na contramão da expectativa popular."),
QuizQuestion(id:459,question:"O que Jesus fez ao expulsar os vendilhões do templo?",options:["Pediu para saírem gentilmente","Derrubou as mesas dos cambistas e as cadeiras dos que vendiam pombas","Reformou o sistema do templo","Apenas ensinou ali"],correctIndex:1,explanation:"Mt 21:12-13: Jesus purificou o templo com autoridade messiânica, cumprindo Malaquias 3:1 ('o Senhor virá de repente ao seu templo') e Jeremias 7:11.",reference:"Mateus 21:12-13",category:.geral,propheticMeaning:"A purificação do templo é ato messiânico — o próprio Senhor do templo limpando sua casa. Hoje a Igreja é o templo (1 Co 3:16-17) e Cristo igualmente purifica o que corrompe a adoração autêntica."),
QuizQuestion(id:460,question:"O que Jesus disse no Getsêmani antes de ser preso?",options:["'Pai, quero morrer logo'","'Pai, se possível, passe de mim este cálice","'Pai, salva-me desta hora'","'Pai, enviai os anjos'"],correctIndex:1,explanation:"Mt 26:39: no Getsêmani, Jesus orou com angústia mas submissão total — 'não como eu quero, mas como tu queres.' A oração perfeita que aceita a vontade do Pai.",reference:"Mateus 26:39",category:.geral,propheticMeaning:"A oração do Getsêmani revela a plenitude da humanidade de Cristo (angústia real) e sua perfeita obediência (submissão ao Pai) — contraste com Adão que escolheu sua própria vontade em vez da de Deus."),
QuizQuestion(id:461,question:"Quais foram as últimas sete palavras de Jesus na cruz?",options:["Apenas uma declaração final","As sete declarações: Pai perdoa-os","Apenas 'está consumado'","Apenas a oração do Pai Nosso"],correctIndex:1,explanation:"Os quatro Evangelhos registram sete declarações de Jesus na cruz — expressando perdão, promessa, amor filial, abandono sentido, humanidade, cumprimento e confiança.",reference:"Lucas 23:34,43,46; João 19:26-27,28,30; Mateus 27:46",category:.geral,propheticMeaning:"'Está consumado' (tetelestai) é a declaração de que a obra redentora foi completamente realizada — não 'acabou' mas 'foi levada ao perfeito cumprimento.' A divida do pecado foi paga integralmente."),
QuizQuestion(id:462,question:"O que é a 'descida ao Hades' de Cristo entre a morte e ressurreição?",options:["Cristo foi ao inferno para sofrer mais","Cristo 'proclamou' sua vitória aos espíritos presos","Cristo foi ao Paraíso apenas","Cristo ficou no túmulo apenas"],correctIndex:1,explanation:"1 Pe 3:18-20 menciona Cristo 'pregando aos espíritos em prisão.' Ef 4:9 fala de descida às regiões inferiores. A interpretação exata é debatida, mas a vitória total é clara.",reference:"1 Pedro 3:18-20; Efésios 4:9",category:.geral,propheticMeaning:"A descida de Cristo ao Hades (seja qual for a interpretação exata) afirma que não há esfera da existência — nem a morte — que Cristo não tenha conquistado e sobre a qual não reine."),
QuizQuestion(id:463,question:"Quem foi a primeira testemunha a quem Jesus apareceu ressurreto?",options:["Pedro","João","Maria Madalena","Tiago"],correctIndex:2,explanation:"João 20:11-18: Jesus apareceu primeiro a Maria Madalena no jardim — ela o confundiu com o hortelão até ele chamar seu nome. 'Maria!' ela reconheceu: 'Rabboni!'",reference:"João 20:14-16",category:.geral,propheticMeaning:"Jesus chamando Maria pelo nome revela que o Ressurreto conhece cada ovelha pelo nome (Jo 10:3) — a ressurreição não é evento abstrato mas encontro pessoal e amoroso."),
QuizQuestion(id:464,question:"O que aconteceu no encontro com os discípulos de Emaús?",options:["Jesus apareceu e desapareceu rapidamente","Dois discípulos caminhavam tristes","Jesus enviou um anjo a eles","Pedro encontrou os discípulos"],correctIndex:1,explanation:"Lc 24:13-35: na caminhada a Emaús, Jesus explicou que o Messias devia sofrer e ressuscitar. Foi reconhecido no partir do pão e desapareceu — seus corações ardiam enquanto ele explicava as Escrituras.",reference:"Lucas 24:13-35",category:.geral,propheticMeaning:"'Nossos corações não ardiam dentro de nós?' (Lc 24:32) — o Espírito iluminando as Escrituras para revelar Cristo ainda faz corações arderem hoje. O padrão Emaús (Escrituras + Ceia) é o padrão do culto cristão."),
QuizQuestion(id:465,question:"O que Jesus disse quando apareceu aos discípulos reunidos no Cenáculo?",options:["'Onde estava a fé de vocês?'","'A paz seja convosco'","'Por que choravam?'","'Por que não me reconheceram?'"],correctIndex:1,explanation:"Jo 20:19-23: Jesus apareceu, disse 'A paz seja convosco', mostrou as feridas como prova, soprou o Espírito Santo e os enviou como o Pai o havia enviado.",reference:"João 20:19-23",category:.geral,propheticMeaning:"'A paz seja convosco' (shalom) pronunciada pelo Ressurreto é a paz que conquistou na cruz (Ef 2:14) — agora oferecida pessoalmente. O sopro do Espírito ecoa Gênesis 2:7, inaugurando a nova criação."),
QuizQuestion(id:466,question:"O que Tomé disse sobre a ressurreição e como Jesus respondeu?",options:["Tomé acreditou imediatamente","Tomé duvidou e disse precisaria ver as feridas","Tomé nunca acreditou","Jesus repudiou Tomé"],correctIndex:1,explanation:"Jo 20:24-29: Tomé duvidou, Jesus apareceu e mostrou as feridas. Tomé declarou 'Senhor meu e Deus meu!' — a mais alta confissão de Cristo no NT. Jesus abençoou 'os que não viram e creram.'",reference:"João 20:24-29",category:.geral,propheticMeaning:"A confissão de Tomé 'Senhor meu e Deus meu' é o clímax do Evangelho de João — o evangelho foi escrito para que 'creiamos que Jesus é o Cristo, o Filho de Deus' (Jo 20:31)."),
QuizQuestion(id:467,question:"O que é a restauração de Pedro em João 21?",options:["Pedro foi punido pelas três negações","Jesus perguntou três vezes 'amas-me?' a Pedro (espelhando as três","Pedro prometeu nunca negar Jesus novamente","Jesus ignorou as negações de Pedro"],correctIndex:1,explanation:"Jo 21:15-17: Jesus perguntou três vezes se Pedro o amava (usando agapaō e phileō) — restaurando cada negação com um recomissionamento pastoral.",reference:"João 21:15-17",category:.geral,propheticMeaning:"A restauração tríplice de Pedro é o modelo da graça restauradora de Cristo — não apenas perdão mas recomissionamento. A falha não desqualifica o servo; a graça o recapacita e o restaura."),
QuizQuestion(id:468,question:"Qual é o significado da Ascensão de Cristo para a missão da Igreja?",options:["Cristo nos abandonou","A Ascensão exaltou Cristo ao trono cósmico (At 1:9-11","Cristo ficou na terra em forma espiritual","A Ascensão marcou o fim do ministério de Cristo"],correctIndex:1,explanation:"A Ascensão é a entronização de Cristo à direita do Pai — de onde intercede (Hb 7:25), envia o Espírito (Jo 16:7) e governará até que todos os inimigos sejam postos como escabelo (Sl 110:1).",reference:"Atos 1:9-11; João 16:7",category:.geral,propheticMeaning:"A Ascensão é condição para o Pentecostes — Cristo 'tendo recebido do Pai a promessa do Espírito Santo, derramou isto que vós vedes e ouvis' (At 2:33). A missão universal da Igreja depende do trono exaltado de Cristo."),
QuizQuestion(id:469,question:"O que aconteceu no Pentecostes em Atos 2?",options:["Um grande terremoto","O Espírito Santo desceu como vento e línguas de fogo sobre 120","Uma visão de Paulo","A chegada dos Magos"],correctIndex:1,explanation:"Atos 2: o Espírito desceu, todos falaram línguas, Pedro pregou sobre a ressurreição de Cristo, e 3.000 pessoas creram e foram batizadas naquele dia.",reference:"Atos 2:1-41",category:.geral,propheticMeaning:"3.000 convertidos no Pentecostes reversa Êxodo 32:28 onde 3.000 morreram pelo pecado do bezerro de ouro — a lei matou 3.000; o Espírito vivificou 3.000. A graça sempre excede o julgamento."),
QuizQuestion(id:470,question:"O que pregou Pedro no Pentecostes?",options:["Sobre o fim do mundo","Que o Jesus que crucificaram é o Cristo ressurreto e exaltado","Uma coleção de profecias","Uma defesa legal dos discípulos"],correctIndex:1,explanation:"Atos 2:14-40: Pedro pregou a primeira mensagem cristã pública — a ressurreição de Jesus cumprindo as Escrituras e o apelo ao arrependimento e batismo.",reference:"Atos 2:36-38",category:.geral,propheticMeaning:"O primeiro sermão cristão termina: 'saibai, pois, toda a casa de Israel, que Deus constituiu Senhor e Cristo a esse Jesus que vós crucificastes' (At 2:36) — o evangelho primitivo é cristocêntrico e histórico."),
QuizQuestion(id:471,question:"Qual é o padrão da vida da Igreja primitiva em Atos 2:42?",options:["Reuniões semanais apenas","'Perseveravam na doutrina dos apóstolos, na comunhão","Evangelismo sem comunidade","Apenas oração e jejum"],correctIndex:1,explanation:"Atos 2:42 lista os quatro pilares da Igreja primitiva: doutrina apostólica, comunhão (koinonia), ceia do Senhor e oração — o padrão normativo para a Igreja em todos os tempos.",reference:"Atos 2:42",category:.geral,propheticMeaning:"Os quatro pilares correspondem aos meios de graça: a Palavra (doutrina), o amor (comunhão), os sacramentos (ceia) e a oração — Deus usando meios ordinários para sustentar a vida extraordinária do povo."),
QuizQuestion(id:472,question:"O que foi o primeiro milagre da Igreja primitiva em Atos 3?",options:["A cura de um cego","Pedro e João curaram um cojo de nascença que pedia esmola na porta do","A ressurreição de Lázaro","A cura de leprosos"],correctIndex:1,explanation:"Atos 3:6: Pedro disse ao paralítico 'Prata e ouro não tenho, porém o que tenho isso te dou: em nome de Jesus Cristo de Nazaré, levanta-te e anda.' — ele se levantou.",reference:"Atos 3:6-8",category:.geral,propheticMeaning:"'Prata e ouro não tenho' — a Igreja apostólica operou com autoridade espiritual sem apoio institucional. Quando a Igreja tem muita prata e ouro (poder e riqueza), frequentemente perde o que Paulo tinha: o nome de Jesus."),
QuizQuestion(id:473,question:"O que é o 'sermão de Pedro' após a cura do cojo em Atos 3?",options:["Uma defesa legal","Pedro pregou que a cura foi pelo nome de Jesus","Uma explicação médica","Uma citação de Moisés"],correctIndex:1,explanation:"Atos 3:11-26: Pedro aproveita o milagre para proclamar o evangelho — o Jesus negado e ressurreto é o cumprimento dos profetas, e o arrependimento traz 'tempos de refrigério da presença do Senhor.'",reference:"Atos 3:19",category:.geral,propheticMeaning:"'Tempos de refrigério' (Atos 3:19) é a antecipação do descanso escatológico — o arrependimento agora já traz refrigério e prepara para a restauração plena na volta de Cristo."),
QuizQuestion(id:474,question:"Qual foi a primeira perseguição da Igreja registrada em Atos?",options:["Por Nero","O Sinédrio prendeu Pedro e João após a cura do cojo e sua pregação","Por Herodes Antipas","Por Paulo (antes da conversão)"],correctIndex:1,explanation:"Atos 4: Pedro e João foram presos pelo Sinédrio (sumo-sacerdotes e saduceus) mas responderam com ousadia diante do conselho que os havia julgado.",reference:"Atos 4:1-4",category:.geral,propheticMeaning:"'Não podemos deixar de falar das coisas que vimos e ouvimos' (At 4:20) — a ousadia dos apóstolos diante de ameaças é resultado do Espírito e da presença do Ressurreto, não de coragem natural."),
QuizQuestion(id:475,question:"O que Paulo e Barnabé fizeram na primeira viagem missionária?",options:["Foram ao Egito","Pregaram em Chipre, Pisídia, Icônio, Listra e Derbe","Foram apenas a Antioquia","Evangelizaram Roma"],correctIndex:1,explanation:"Atos 13-14: a primeira viagem missionária de Paulo e Barnabé percorreu Chipre e o sul da Galácia, fundando igrejas que Paulo visitaria novamente e às quais escreveria Gálatas.",reference:"Atos 13:1-3; 14:21-23",category:.geral,propheticMeaning:"A primeira viagem missionária foi iniciada pelo Espírito Santo separando Paulo e Barnabé (At 13:2) — a missão cristã não começa com estratégia humana mas com obediência ao Espírito."),
QuizQuestion(id:476,question:"O que é a segunda viagem missionária de Paulo?",options:["Apenas para a Galácia","Paulo levou Silas, visitou as igrejas da Galácia","Paulo foi a Roma","Paulo visitou o Egito e Etiópia"],correctIndex:1,explanation:"Atos 15:36-18:22: a segunda viagem de Paulo com Silas trouxe o evangelho à Europa — Filipos (primeira convertida: Lídia), Tessalônica, Bereia, Atenas (Areópago) e Corinto.",reference:"Atos 16:9-10",category:.geral,propheticMeaning:"A visão do homem macedônio ('vem e ajuda-nos') revela como Deus guia a missão — uma visão noturna redirecionou o evangelho para a Europa, mudando o curso da história ocidental e mundial."),
QuizQuestion(id:477,question:"O que é a terceira viagem missionária de Paulo?",options:["Sua viagem a Roma","Paulo pregou em Éfeso por três anos (base para toda a Ásia)","Paulo retornou à Galácia","Paulo foi preso em Corinto"],correctIndex:1,explanation:"Atos 18:23-21:16: Paulo pregou em Éfeso por 3 anos (base para toda a Ásia Menor), escreveu 1 e 2 Coríntios e Romanos, fez coleta para os pobres de Jerusalém.",reference:"Atos 19:10; 20:17-38",category:.geral,propheticMeaning:"O discurso de Paulo aos presbíteros de Éfeso em Mileto (At 20:17-38) é o único discurso no NT dirigido a cristãos — e é sobre liderança pastoral, servindo como modelo para todos os pastores."),
QuizQuestion(id:478,question:"Como Paulo chegou a Roma para ser julgado?",options:["Por iniciativa própria","Apelou ao César como cidadão romano após ser preso em Jerusalém","Foi convidado pelos romanos","Foi enviado pela Igreja de Antioquia"],correctIndex:1,explanation:"Atos 21-28: Paulo foi preso em Jerusalém, transferido para Cesareia, apelou ao César, naufragou em Malta e chegou a Roma — cumprindo At 23:11: 'Como testificaste as coisas de mim em Jerusalém, assim te cumpre testificar também em Roma.'",reference:"Atos 23:11; 28:16",category:.geral,propheticMeaning:"A prisão de Paulo e sua chegada a Roma cumpre a estratégia divina — Deus usou a prisão para levar Paulo ao coração do Império. Deus usa até a perseguição para avançar o evangelho (Fp 1:12-14)."),
QuizQuestion(id:479,question:"Qual é a última cena do livro de Atos?",options:["Paulo sendo executado","Paulo em Roma pregando o Reino de Deus 'com toda a ousadia","Paulo sendo libertado da prisão","Os apóstolos reunidos em Jerusalém"],correctIndex:1,explanation:"Atos 28:30-31: Paulo em Roma por dois anos 'recebia a todos os que vinham ter com ele, pregando o reino de Deus e ensinando as coisas relativas ao Senhor Jesus Cristo.' Final aberto.",reference:"Atos 28:30-31",category:.geral,propheticMeaning:"O final aberto de Atos é intencional — a história da expansão do Espírito não acabou com Paulo; cada geração de crentes é o próximo capítulo do mesmo livro em andamento."),
QuizQuestion(id:480,question:"O que Paulo ensina sobre orar pelo Espírito em Romanos 8:26-27?",options:["O Espírito não nos ajuda a orar","'O Espírito intercede por nós com gemidos inexprimíveis' quando não","A oração depende apenas de nossa habilidade","Devemos orar apenas em línguas"],correctIndex:1,explanation:"Rm 8:26-27: o Espírito Santo intercede por nós com 'gemidos inexprimíveis' quando somos fracos demais para saber como orar — Deus mesmo supre nossa limitação na oração.",reference:"Romanos 8:26-27",category:.geral,propheticMeaning:"Com Cristo intercedendo no trono (Rm 8:34) e o Espírito intercedendo em nós (Rm 8:26), o crente fraco é sustentado por dupla intercessão trinitária — a oração cristã nunca depende apenas de nossa força."),
QuizQuestion(id:481,question:"O que é a 'guerra espiritual' segundo Efésios 6:12?",options:["Luta contra pessoas","'Nossa luta não é contra a carne e o sangue","Batalhas políticas","Conflitos na Igreja"],correctIndex:1,explanation:"Ef 6:12: a batalha cristã real é espiritual — contra forças demoníacas e estruturas do mal, não contra pessoas. Por isso a armadura é espiritual.",reference:"Efésios 6:12",category:.geral,propheticMeaning:"Reconhecer a dimensão espiritual da realidade não é demonização das pessoas mas libertação da ilusão de que os problemas são apenas humanos — a intercessão e a Palavra são as armas primárias."),
QuizQuestion(id:482,question:"O que Paulo ensina sobre a morte em Filipenses 1:21?",options:["A morte é o fim de tudo","'Para mim o viver é Cristo e o morrer é lucro'","A morte deve ser evitada a todo custo","A morte é um fracasso espiritual"],correctIndex:1,explanation:"Fp 1:21-23: Paulo vive em tensão entre continuar no corpo (necessário pela Igreja) e partir para estar com Cristo (muito melhor) — para ele, viver e morrer têm o mesmo resultado: Cristo.",reference:"Filipenses 1:21-23",category:.geral,propheticMeaning:"'Morrer é lucro' inverte completamente a lógica mundana do terror da morte — o evangelho cura o medo existencial humano ao transformar a morte de fim em porta de entrada para a presença plena de Cristo."),
QuizQuestion(id:483,question:"O que Paulo diz sobre o contentamento em Filipenses 4:11?",options:["O contentamento vem de ter muito","'Aprendi a estar contente em qualquer estado em que me encontre'","Contentamento significa não ter ambições","Só podemos estar contentes com saúde"],correctIndex:1,explanation:"Fp 4:11: Paulo 'aprendeu' contentamento (não nasceu com ele) — tanto na abundância quanto na necessidade, o segredo é Cristo que o fortalece (v.13).",reference:"Filipenses 4:11-13",category:.geral,propheticMeaning:"O contentamento aprendido é a libertação do consumismo — não ascetismo (evitar bens) mas apatheia cristã (bens não controlam). Paulo pode ter muito ou pouco porque sua identidade está em Cristo, não nas posses."),
QuizQuestion(id:484,question:"O que é a 'glória futura' que Paulo menciona em Romanos 8:18?",options:["Prosperidade nesta vida","'As aflições do tempo presente não podem ser comparadas com a glória","Recompensas materiais após morte","A glória da Igreja na terra"],correctIndex:1,explanation:"Rm 8:18: toda a criação geme aguardando a revelação dos filhos de Deus — a glória futura é tão superior ao sofrimento presente que não admite comparação.",reference:"Romanos 8:18-23",category:.geral,propheticMeaning:"A criação aguardando com gemidos (Rm 8:22) revela que a redenção final é cósmica — não apenas almas salvas, mas nova criação inteira. O evangelicalismo que espera apenas a destruição do mundo perde a visão de Paulo."),
QuizQuestion(id:485,question:"O que Paulo diz sobre o 'espinho na carne' e a resposta de Deus?",options:["Deus removeu imediatamente","Paulo pediu três vezes a remoção","Deus ignorou o pedido","Paulo parou de pedir"],correctIndex:1,explanation:"2 Co 12:7-10: Deus não removeu o 'espinho' mas revelou que a fraqueza é o palco onde sua graça brilha mais. Paulo passou a 'gloriar-se nas fraquezas.'",reference:"2 Coríntios 12:7-10",category:.geral,propheticMeaning:"'O poder se aperfeiçoa na fraqueza' inverte toda a teologia da prosperidade — Deus frequentemente glorifica mais em nossos fracassos do que em nossos sucessos, porque assim a glória é claramente sua, não nossa."),
QuizQuestion(id:486,question:"Qual é a ética do trabalho segundo Paulo em 2 Tessalonicenses 3:10?",options:["Os crentes não devem trabalhar aguardando a volta de Cristo","'Se alguém não quiser trabalhar, também não coma'","O trabalho é maldição a ser evitada","Apenas os pobres devem trabalhar"],correctIndex:1,explanation:"2 Ts 3:10-12: Paulo ordena trabalho regular e tranquilo, contra o ócio motivado pela expectativa equivocada da volta iminente de Cristo.",reference:"2 Tessalonicenses 3:10-12",category:.geral,propheticMeaning:"A ética do trabalho de Paulo fundamenta a 'teologia do trabalho' cristã: trabalho não é apenas necessidade mas vocação — participação no cuidado de Deus pelo mundo (Gn 1:28; 2:15)."),
QuizQuestion(id:487,question:"Qual é o tema central de Colossenses?",options:["Os dons espirituais","A supremacia cósmica de Cristo: 'primogênito de toda a criação...","As regras do casamento","A segunda vinda"],correctIndex:1,explanation:"Colossenses 1:15-20 (o 'hino cristológico') exalta Cristo como criador, sustentador e redentor de tudo — resposta à heresia proto-gnóstica que minimizava Cristo.",reference:"Colossenses 1:15-20",category:.geral,propheticMeaning:"'Nele habitam corporalmente toda a plenitude da divindade' (Cl 2:9) é a refutação de toda cristologia que diminui Cristo — ele não é um de muitos mediadores, mas o único em quem habita toda a plenitude divina."),
QuizQuestion(id:488,question:"O que Paulo ensina sobre o perdão em Colossenses 3:13?",options:["Perdoe apenas três vezes","'Suportando-vos uns aos outros e perdoando-vos mutuamente... assim","O perdão é opcional","Perdoe apenas se a pessoa pedir"],correctIndex:1,explanation:"Cl 3:13: o padrão do perdão cristão é o perdão de Cristo — ilimitado, imerecido e que não depende de a outra parte 'merecer.' É a graça que recebemos repassada.",reference:"Colossenses 3:13",category:.geral,propheticMeaning:"'Assim como o Senhor vos perdoou' estabelece o padrão do perdão: gratuito, total, sem guardar rancor. É impossível sem o Espírito que derrama o amor de Deus nos corações (Rm 5:5)."),
QuizQuestion(id:489,question:"O que é a 'comunhão dos santos' na fé cristã?",options:["Uma festa anual","A koinonia — comunidade viva de todos os crentes, unidos em Cristo","Apenas a Ceia do Senhor","A reunião semanal na Igreja"],correctIndex:1,explanation:"Koinonia (At 2:42; 1 Jo 1:3) é mais que socialização — é participação compartilhada na vida trinitária, unindo crentes de todas as épocas em Cristo.",reference:"Atos 2:42; 1 João 1:3",category:.geral,propheticMeaning:"A comunhão transcende o tempo — 'a comunhão dos santos' inclui os que já partiram (Hb 12:1; 12:22-24). A morte não quebra a koinonia porque o Cristo que nos une é vivo e eterno."),
QuizQuestion(id:490,question:"Qual é a 'oração sumária' de João 17 (Oração Sacerdotal)?",options:["Pai Nosso repetido","A oração mais longa de Jesus registrada no NT: pedindo glória","Uma oração pelo templo","Uma oração pela conversão de Israel"],correctIndex:1,explanation:"João 17 é a 'Oração Sacerdotal' de Jesus antes da paixão: pede gloria (v.1-5), proteção dos discípulos (v.6-19) e unidade de todos os que crerão (v.20-26).",reference:"João 17:21",category:.geral,propheticMeaning:"'Para que todos sejam um, como tu, ó Pai, és em mim e eu em ti' (Jo 17:21) — a unidade que Jesus pede é participação na unidade trinitária: amor e comunhão como a que existe entre Pai e Filho."),
QuizQuestion(id:491,question:"O que significa 'santificação' na vida cristã?",options:["Tornar-se perfeito instantaneamente","O processo progressivo de ser separado para Deus e transformado à","Participar de rituais religiosos","Evitar pecados específicos somente"],correctIndex:1,explanation:"Santificação é o processo pelo qual o crente é progressivamente transformado à imagem de Cristo (2 Co 3:18), cooperando com o Espírito (Fp 2:12-13).",reference:"2 Coríntios 3:18; Filipenses 2:12-13",category:.geral,propheticMeaning:"'Transformados de glória em glória' (2 Co 3:18) — a santificação é progressiva, não instantânea. O crente é declarado santo (justificação) e torna-se santo (santificação) — o 'já' e o 'ainda não' aplicados ao caráter."),
QuizQuestion(id:492,question:"O que Paulo ensina sobre a carne em Gálatas 5:19-21?",options:["A carne é o corpo físico","As obras da carne são os frutos da natureza pecaminosa: imoralidade","A carne é sempre boa","Apenas os grandes pecados excluem do reino"],correctIndex:1,explanation:"Gálatas 5:19-21 lista as obras da carne — frutos da natureza pecaminosa não transformada — em contraste com o fruto do Espírito (v.22-23).",reference:"Gálatas 5:19-21",category:.geral,propheticMeaning:"A lista das obras da carne em Gálatas 5 inclui tanto pecados 'físicos' (imoralidade) quanto pecados 'espirituais' (ódios, inveja, dissensões) — nenhum é aceitável para o que vive segundo o Espírito."),
QuizQuestion(id:493,question:"Qual é o 'mistério da piedade' em 1 Timóteo 3:16?",options:["A natureza da Trindade","'Grande é o mistério da piedade: Deus foi manifestado em carne","Os dons espirituais","A segunda vinda"],correctIndex:1,explanation:"1 Tm 3:16 é um hino cristológico primitivo resumindo o movimento de Cristo: encarnação, ressurreição, aparição, proclamação, fé e exaltação.",reference:"1 Timóteo 3:16",category:.geral,propheticMeaning:"O 'mistério da piedade' é o coração do evangelho em forma poética — Deus entrou no mundo (encarnação) e o mundo entrou em Deus (exaltação). Cristo conecta criação e Criador para sempre."),
QuizQuestion(id:494,question:"O que é 'a vontade de Deus' segundo Romanos 12:1-2?",options:["A prosperidade dos crentes","Apresentar o corpo como sacrifício vivo","Guardar todos os rituais","Ter saúde e riqueza"],correctIndex:1,explanation:"Rm 12:1-2: a vontade de Deus é descoberta através da consagração total (v.1) e da renovação da mente (v.2) — não revelação mágica mas discernimento progressivo.",reference:"Romanos 12:1-2",category:.geral,propheticMeaning:"A vontade de Deus é 'boa, agradável e perfeita' — não algo a ser temido mas desejado. O discernimento vem pela mente renovada e pelo coração consagrado, não por sinais e sonhos somente."),
QuizQuestion(id:495,question:"O que Paulo ensina sobre raiva em Efésios 4:26?",options:["Nunca se irrite","'Irai-vos e não pequeis; não se ponha o sol sobre a vossa ira'","A ira sempre é pecado","Ignore os conflitos"],correctIndex:1,explanation:"Ef 4:26: a raiva pode ser justa (Jesus se irou Mt 21:12) mas não deve ser alimentada ou transformada em rancor. Resolva os conflitos antes de dormir.",reference:"Efésios 4:26-27",category:.geral,propheticMeaning:"'Não deis lugar ao diabo' (v.27) — o rancor não resolvido é 'espaço' que abrimos ao diabo. A reconciliação rápida é proteção espiritual, não apenas cortesia social."),
QuizQuestion(id:496,question:"Qual é o maior mandamento segundo Deuteronômio 6:4-5 (Shemá)?",options:["Guardar o sábado","'Ouve, ó Israel, o Senhor nosso Deus é o único Senhor. E amarás o","Não matar","Não ter outros deuses"],correctIndex:1,explanation:"O Shemá (Dt 6:4-9) é o credo central do judaísmo e foi citado por Jesus como o maior mandamento: amor a Deus como resposta ao monoteísmo radical.",reference:"Deuteronômio 6:4-5; Marcos 12:29-30",category:.geral,propheticMeaning:"'Com todo o coração, alma e força' — totalidade sem reservas. Jesus acrescentou 'e com todo o teu entendimento' (Mc 12:30) — o amor a Deus envolve emoção, vontade, poder e racionalidade."),
QuizQuestion(id:497,question:"O que é a 'lei natural' segundo Paulo em Romanos 2:14-15?",options:["As leis da natureza física","Os gentios que não têm a lei de Moisés mostram a obra da lei em seus...","Que gentios estão automaticamente salvos","Que a lei mosaica é desnecessária"],correctIndex:1,explanation:"Rm 2:14-15: os gentios demonstram pelo comportamento moral que a lei está escrita em seus corações — responsabilidade universal perante Deus, sem desculpa.",reference:"Romanos 2:14-15",category:.geral,propheticMeaning:"A consciência moral universal é o fundamento da responsabilidade humana perante Deus — todos têm suficiente luz para ser responsáveis, e o evangelho é a plena luz que satisfaz o que a lei natural aponta mas não pode cumprir."),
QuizQuestion(id:498,question:"O que Paulo ensina sobre a administração do tempo em Efésios 5:15-16?",options:["Não se preocupe com o tempo","'Andai com diligência... remindo o tempo, porquanto os dias são maus'","Descanse muito","Trabalhe sem parar"],correctIndex:1,explanation:"Ef 5:15-16: 'Remir o tempo' (exagorázomenoi) significa comprar de volta, aproveitar ao máximo cada oportunidade — viver com consciência escatológica da brevidade do tempo.",reference:"Efésios 5:15-16",category:.geral,propheticMeaning:"'Os dias são maus' — a urgência da missão e da vida piedosa vem do reconhecimento de que o tempo é escasso e valioso. Cada dia não aproveitado para o reino é irrecuperável."),
QuizQuestion(id:499,question:"O que Paulo diz sobre o casamento de crentes com não crentes em 2 Coríntios 6:14?",options:["É proibido mas permitido com condições","'Não vos ponhais em jugo desigual com os incrédulos'","É incentivado para evangelizar","É apenas uma sugestão"],correctIndex:1,explanation:"2 Co 6:14-16: o 'jugo desigual' cria incompatibilidade fundamental — como trevas e luz, justiça e iniquidade. Paulo aplica especialmente ao casamento e associações íntimas.",reference:"2 Coríntios 6:14-16",category:.geral,propheticMeaning:"O princípio do jugo desigual vem de Levítico 19:19 (não misturar espécies). No NT, é aplicado espiritualmente — não segregação social, mas reconhecimento de que a lealdade primária determina os relacionamentos mais íntimos."),
QuizQuestion(id:500,question:"O que significa ser 'cheio do Espírito Santo'?",options:["Uma emoção religiosa intensa","O controle e governo contínuo do Espírito sobre toda a vida do crente","Falar em línguas apenas","Uma experiência única e irrepetível"],correctIndex:1,explanation:"Ef 5:18: 'sede cheios do Espírito' (presente contínuo) — contraste com embriaguez. Ser cheio é ser constantemente controlado, motivado e empoderado pelo Espírito.",reference:"Efésios 5:18",category:.geral,propheticMeaning:"O mesmo Espírito que encheu os discípulos no Pentecostes está disponível a todos os crentes — a 'plenitude' não é reserva para alguns; Paulo manda que todos sejam cheios, sendo um processo contínuo e renovável."),
QuizQuestion(id:501,question:"Qual é a diferença entre fé e esperança segundo Hebreus 11:1?",options:["São a mesma coisa","Fé é o firme fundamento do que se espera e prova do que não se vê","Esperança é mais forte que fé","Fé é para o presente; esperança para o passado"],correctIndex:1,explanation:"Hb 11:1: a fé e a esperança são inseparáveis — a fé se apoia em Deus agora; a esperança olha para o que ele prometeu e ainda não cumpriu completamente.",reference:"Hebreus 11:1; Romanos 8:24-25",category:.geral,propheticMeaning:"'Esperança que se vê não é esperança' (Rm 8:24) — a esperança cristã sempre olha para além do presente. A tensão fé-esperança mantém o crente orientado para o futuro de Deus, não apenas para as bênçãos presentes."),
QuizQuestion(id:502,question:"O que Paulo diz sobre a viuvez e o segundo casamento em 1 Coríntios 7?",options:["Nunca se case novamente","A viúva é livre para casar novamente","Deve casar imediatamente","O segundo casamento é pecado"],correctIndex:1,explanation:"1 Co 7:39-40: Paulo liberta viúvas para casar novamente, mas 'somente no Senhor' — e adiciona sua opinião pessoal: permanecer solteira é mais feliz (na situação de tribulação da época).",reference:"1 Coríntios 7:39-40",category:.geral,propheticMeaning:"Paulo distinguindo sua 'opinião' da palavra do Senhor (1 Co 7:25,40) demonstra honestidade intelectual e transparência apostólica — modela como diferenciar Escritura da reflexão pastoral."),
QuizQuestion(id:503,question:"O que é a 'caminhada em amor' de Efésios 5:2?",options:["Um ritual de adoração","Andar em amor 'como também Cristo vos amou e se entregou a si mesmo","Uma prática de meditação","O amor romântico"],correctIndex:1,explanation:"Ef 5:2: a caminhada em amor tem como padrão o amor sacrificial de Cristo — sua entrega total é o modelo e motivação do amor cristão uns pelos outros.",reference:"Efésios 5:2",category:.geral,propheticMeaning:"'Como Cristo vos amou' — o amor cristão não é baseado nos sentimentos do momento mas no modelo e poder de Cristo. O mesmo amor que Cristo exerceu, ele derrama em nós pelo Espírito (Rm 5:5)."),
QuizQuestion(id:504,question:"Qual é a promessa de 2 Coríntios 4:17?",options:["Que não haverá sofrimento","'A nossa leve e momentânea tribulação produz para nós um peso eterno","Que seremos curados de toda doença","Que a prosperidade virá cedo"],correctIndex:1,explanation:"2 Co 4:17: Paulo chama seus imensos sofrimentos (2 Co 11:23-28) de 'leve e momentânea tribulação' em contraste com a glória eterna — perspectiva escatológica que relativiza o sofrimento presente.",reference:"2 Coríntios 4:17",category:.geral,propheticMeaning:"O sofrimento 'produz' glória — não automaticamente mas quando fixamos os olhos no invisível eterno (v.18). A perspectiva escatológica é a cura para o desespero presente."),
QuizQuestion(id:505,question:"O que Paulo ensina sobre a imoralidade sexual em 1 Coríntios 6:18-20?",options:["É permitida fora do casamento","'Fugi da imoralidade sexual. Todo pecado que o homem comete é fora do","É apenas uma questão cultural","É pecado apenas se magoar alguém"],correctIndex:1,explanation:"1 Co 6:18-20: a imoralidade sexual é única em profanar o corpo que é templo do Espírito Santo — razão adicional para a pureza sexual cristã.",reference:"1 Coríntios 6:18-20",category:.geral,propheticMeaning:"'Não sois vossos, porque fostes comprados por preço' (1 Co 6:20) — a pureza sexual não é repressão mas reconhecimento de que nossos corpos pertencem a Cristo que os redimiu com seu sangue."),
QuizQuestion(id:506,question:"O que Paulo ensina sobre a renovação da mente em Romanos 12:2?",options:["Pense positivo","A transformação (metamorfose) pela renovação do entendimento","Memorize a Bíblia apenas","Pense apenas em coisas espirituais"],correctIndex:1,explanation:"Rm 12:2: 'metamorfoseio' — a mesma palavra da Transfiguração — indica que a transformação do crente é profunda, de dentro para fora, começando pela mente.",reference:"Romanos 12:2",category:.geral,propheticMeaning:"A 'renovação do entendimento' é obra do Espírito que usa a Palavra para reformar nossa visão de realidade — substituindo os valores do século pelo pensamento de Cristo (1 Co 2:16)."),
QuizQuestion(id:507,question:"Quem foi Priscila e Áquila?",options:["Dois profetas do AT","Um casal de tendeiros que trabalharam com Paulo","Dois apóstolos","Líderes do Sinédrio convertidos"],correctIndex:1,explanation:"Atos 18:2-3,26: Priscila e Áquila, expulsos de Roma por Cláudio, encontraram Paulo em Corinto, viajaram com ele para Éfeso onde instruíram Apollos e tinham Igreja em sua casa.",reference:"Atos 18:2-3,26; Romanos 16:3-4",category:.geral,propheticMeaning:"Priscila sendo mencionada antes de Áquila em vários textos sugere que ela tinha papel de liderança — o Espírito usa homens e mulheres em serviço ao Reino conforme prometido em Joel 2."),
QuizQuestion(id:508,question:"O que Paulo ensina sobre a ceia do Senhor em 1 Coríntios 11:27-29?",options:["Qualquer pessoa pode participar a qualquer hora","'Quem comer o pão ou beber o cálice do Senhor indignamente... come e","A ceia não tem significado especial","Apenas o pastor pode servir a ceia"],correctIndex:1,explanation:"1 Co 11:27-29: participar da Ceia de forma indigna (sem discernir o corpo do Senhor, sem exame próprio) traz juízo — a Ceia exige seriedade e preparação.",reference:"1 Coríntios 11:27-29",category:.geral,propheticMeaning:"'Discernir o corpo do Senhor' inclui discernir tanto o corpo de Cristo na ceia quanto o corpo de Cristo na Igreja — chegar à mesa e ignorar os irmãos em necessidade é desdenhar o corpo (1 Co 11:22)."),
QuizQuestion(id:509,question:"O que é a 'exortação' em Hebreus 3:13?",options:["Uma repreensão dura","'Exortai-vos uns aos outros cada dia, enquanto se pode dizer Hoje","Uma pregação pública","Um ritual de arrependimento"],correctIndex:1,explanation:"Hb 3:13: a exortação mútua diária previne o endurecimento do coração pelo pecado — a comunidade cristã como proteção contra a apostasia.",reference:"Hebreus 3:13",category:.geral,propheticMeaning:"'Enquanto se pode dizer Hoje' — a urgência vem do caráter perecível do tempo de graça. A Igreja existe também como comunidade protetora que impede o isolamento que leva ao endurecimento."),
QuizQuestion(id:510,question:"Qual é o tema de Hebreus 12:1-2?",options:["As profecias do AT","'Visto que também nós temos em derredor de nós tão grande nuvem de","A segunda vinda de Cristo","Os dons espirituais"],correctIndex:1,explanation:"Hb 12:1-2: rodeados pelas testemunhas de Hebreus 11, corremos a corrida com perseverança, 'olhando para Jesus' como modelo e fonte de toda a fé.",reference:"Hebreus 12:1-2",category:.geral,propheticMeaning:"'Olhando para Jesus' (aphoran — foco fixo, olho único) é o segredo da corrida cristã — não os troféus, nem os espectadores, nem as circunstâncias. Christ é o pacemaker e o prêmio simultaneamente."),
QuizQuestion(id:511,question:"O que é 'disciplina do Senhor' em Hebreus 12:5-11?",options:["Punição por falta de fé","'O Senhor disciplina ao que ama e açoita qualquer filho que recebe'","Jejum forçado","Perseguição do diabo"],correctIndex:1,explanation:"Hb 12:5-11: a disciplina de Deus é sinal de amor e filiação — não punição penal mas educação paterna. Produz 'fruto pacífico de justiça para os que por ela foram exercitados.'",reference:"Hebreus 12:5-11",category:.geral,propheticMeaning:"A disciplina paterna distingue filhos de bastardos (v.8) — sofrer a disciplina de Deus é evidência de adoção, não sinal de abandono. O pai que não disciplina não ama seus filhos (Pv 13:24)."),
QuizQuestion(id:512,question:"Qual é a promessa de Tiago 5:16 sobre a oração?",options:["Toda oração é igualmente eficaz","'A oração do justo tem grande poder em seus efeitos'","A oração pública é mais forte","Apenas pastores têm oração eficaz"],correctIndex:1,explanation:"Tiago 5:16: 'a súplica fervorosa do justo tem grande poder' — Tiago cita Elias que era 'de igual natureza que nós' mas orou e o céu se fechou e se abriu.",reference:"Tiago 5:16-17",category:.geral,propheticMeaning:"Elias como exemplo de oração eficaz mostra que a oração poderosa não é exclusiva de super-heróis espirituais — Elias era 'de igual natureza que nós' (paschopathes), sujeito às mesmas emoções humanas."),
QuizQuestion(id:513,question:"O que Pedro ensina sobre os falsos profetas em 2 Pedro 2?",options:["Não existirão falsos profetas","Haverá falsos mestres que 'negarão o Senhor que os resgatou'","Os falsos profetas sempre são óbvios","Ignore os falsos profetas"],correctIndex:1,explanation:"2 Pe 2:1-3: Pedro alerta que falsos profetas introduzirão heresias sorrateiramente, serão seguidos por muitos, e causarão difamação do caminho da verdade.",reference:"2 Pedro 2:1-3",category:.geral,propheticMeaning:"Pedro escrevendo sobre falsos profetas no séc. I ancora o alerta no AT (v.4-10) — o fenômeno não é novo. Jesus, Paulo, João, Tiago e Pedro todos alertaram para o mesmo perigo em cada geração."),
QuizQuestion(id:514,question:"O que João ensina sobre antijristos em 1 João 2:18-22?",options:["Apenas um anticristo virá","'Filhinhos, é a última hora... ouvistes que vem o anticristo","O anticristo é apenas político","Não devemos falar sobre o anticristo"],correctIndex:1,explanation:"1 João 2:18-22: João vê o anticristo como fenômeno já presente — os que saíram da Igreja e negam que Jesus é o Cristo são antijristos.",reference:"1 João 2:18-22",category:.geral,propheticMeaning:"O anticristo ('contra Cristo' ou 'em lugar de Cristo') é espírito presente em todo ensino que substitui Cristo — seja heresia, seja sistema de obras, seja messianismo político. A vigilância é sempre necessária."),
QuizQuestion(id:515,question:"O que Judas diz sobre 'contender pela fé'?",options:["A fé não precisa ser defendida","'Senti a necessidade de vos escrever exortando-vos a contender","A fé muda a cada geração","Contender divide a Igreja"],correctIndex:1,explanation:"Judas 3: 'contender pela fé' (epagonizomai) é luta ativa para preservar o depósito doutrinário contra os que o distorcem sorrateiramente.",reference:"Judas 3",category:.geral,propheticMeaning:"'A fé uma vez por todas entregue aos santos' tem conteúdo fixo — não é uma revelação progressiva que cada geração redefine. O evangelho apostólico é normativo para toda a Igreja em todos os tempos."),
QuizQuestion(id:516,question:"Qual é a visão do trono de Deus em Apocalipse 4?",options:["Um templo terrestre","João viu o trono celestial cercado de arco-íris, 24 anciãos","Uma batalha no céu","O julgamento final"],correctIndex:1,explanation:"Apocalipse 4 revela a sala do trono celestial — o centro real do universo onde adoração incessante ocorre ao redor do Trono e do Cordeiro.",reference:"Apocalipse 4:8-11",category:.geral,propheticMeaning:"A visão do trono em Ap 4 reconfigura a realidade: o verdadeiro poder não está em Roma, Washington ou Pequim, mas no Trono celestial. A adoração é ato político: reconhecer quem realmente governa."),
QuizQuestion(id:517,question:"O que são os sete selos de Apocalipse 6?",options:["Sete cartas para as igrejas","Sete julgamentos sequenciais abertos pelo Cordeiro: os quatro","Sete pecados capitais","Os sete dons do Espírito"],correctIndex:1,explanation:"Apocalipse 6: o Cordeiro abre sete selos revelando julgamentos progressivos — os quatro cavaleiros (conquista, guerra, fome, morte), clamor dos mártires e sinais cósmicos.",reference:"Apocalipse 6:1-17",category:.geral,propheticMeaning:"O Cordeiro abrindo os selos revela que Cristo soberanamente controla todos os eventos históricos — mesmo guerra, fome e morte estão sob seu domínio, não escapando ao seu controle."),
QuizQuestion(id:518,question:"Quem são os 144.000 em Apocalipse 7?",options:["Exatamente 144.000 cristãos literais","Interpretações variam: o Israel completo (12x12.000 das doze tribos)","Os primeiros cristãos","Uma seita específica"],correctIndex:1,explanation:"Ap 7: os 144.000 selados (das doze tribos) e a 'multidão que ninguém podia contar, de toda nação, tribo, povo e língua' — interpretada simbolicamente como a plenitude do povo de Deus.",reference:"Apocalipse 7:4,9",category:.geral,propheticMeaning:"O número simbólico 12 x 12 x 1000 (perfeição x perfeição x completude) indica não uma quantidade literal mas a totalidade completa do povo de Deus — nenhum faltará."),
QuizQuestion(id:519,question:"O que são as sete trombetas em Apocalipse 8-11?",options:["Instrumentos musicais celestiais","Sete julgamentos progressivos que anunciam o fim","Sete anjos mensageiros","As sete festas de Israel"],correctIndex:1,explanation:"Apocalipse 8-11: os sete anjos tocam trombetas anunciando julgamentos que ecoam as pragas do Êxodo em escala cósmica e global.",reference:"Apocalipse 8:6-7",category:.geral,propheticMeaning:"As trombetas ecoando as pragas do Êxodo revelam o padrão de Deus: julgamentos que chamam ao arrependimento (Ap 9:20-21) antes do julgamento final. Deus avisa antes de julgar."),
QuizQuestion(id:520,question:"O que representa a 'mulher revestida de sol' em Apocalipse 12?",options:["Maria, mãe de Jesus apenas","O povo de Deus (Israel e Igreja) que deu à luz o Messias","Uma deusa solar","Roma Imperial"],correctIndex:1,explanation:"Apocalipse 12: a mulher (povo de Deus) revestida de sol, lua e coroas deu à luz o filho varão (Cristo), perseguida pelo dragão que foi lançado à terra.",reference:"Apocalipse 12:1-6",category:.geral,propheticMeaning:"A guerra cósmica de Ap 12 revela a dimensão espiritual da história — o conflito entre o Messias e Satanás (Gn 3:15) está por trás de toda a perseguição histórica contra o povo de Deus."),
QuizQuestion(id:521,question:"Qual é a mensagem do anjo em Apocalipse 14:6-7?",options:["Uma mensagem de guerra","'O evangelho eterno': 'temei a Deus e dai-lhe glória","Um chamado para a batalha","Uma mensagem de paz"],correctIndex:1,explanation:"Ap 14:6-7: o primeiro dos três anjos proclama o 'evangelho eterno' — chamando toda nação ao temor de Deus e adoração ao Criador, antes do julgamento final.",reference:"Apocalipse 14:6-7",category:.geral,propheticMeaning:"O 'evangelho eterno' proclamado por um anjo 'a toda nação, tribo, língua e povo' é a demonstração de que Deus não deixará nenhuma nação sem testemunho antes do julgamento final."),
QuizQuestion(id:522,question:"O que é o 'casamento do Cordeiro' em Apocalipse 19?",options:["Um casamento literal no céu","A união definitiva de Cristo (o Cordeiro) com sua noiva (a Igreja)","Um evento simbólico sem futuro","A restauração de Israel"],correctIndex:1,explanation:"Apocalipse 19:7-9: 'as bodas do Cordeiro' chegaram — 'a noiva se preparou.' Bem-aventurados os convidados para a ceia das bodas do Cordeiro.",reference:"Apocalipse 19:7-9",category:.geral,propheticMeaning:"O casamento do Cordeiro é o cumprimento de todas as metáforas esponsal da Bíblia — desde Oséias e Ezequiel (Israel como esposa de Deus) até Efésios 5 (Igreja como noiva de Cristo). A história termina num casamento."),
QuizQuestion(id:523,question:"O que é o 'julgamento do grande trono branco' em Apocalipse 20?",options:["Um julgamento apenas para os perdidos","O julgamento final diante do qual todos os mortos ressuscitarão para...","Um julgamento apenas dos crentes","Um julgamento dos anjos"],correctIndex:1,explanation:"Apocalipse 20:11-15: o julgamento do grande trono branco envolve a ressurreição de todos os mortos para julgamento final — obras avaliadas, livros abertos, livro da vida determinante.",reference:"Apocalipse 20:11-15",category:.geral,propheticMeaning:"As obras são avaliadas não para determinar salvação (pelo livro da vida) mas para determinar grau de responsabilidade — 'segundo as suas obras' (v.12,13) indica gradação de julgamento e de recompensa."),
QuizQuestion(id:524,question:"Qual é a promessa central de Apocalipse 22:1-5?",options:["Que haverá novas guerras","O rio de água da vida, a árvore da vida, nenhuma maldição","Que haverá um novo templo","Que Jerusalém será capital mundial"],correctIndex:1,explanation:"Ap 22:1-5: a Nova Jerusalém tem rio de vida, árvore da vida, nenhuma maldição, Deus e o Cordeiro são o templo e a luz, e os servos reinarão para sempre.",reference:"Apocalipse 22:1-5",category:.geral,propheticMeaning:"Ap 22:1-5 inverte todas as consequências da queda de Gênesis 3: a maldição removida, o acesso à árvore da vida restaurado, a presença de Deus face a face. É Éden restaurado e superado."),
QuizQuestion(id:525,question:"Qual é a última oração da Bíblia?",options:["O Pai Nosso","'Vem, Senhor Jesus' (Maranata) — Apocalipse 22:20","'Salva-nos, Senhor'","'Glória nas alturas'"],correctIndex:1,explanation:"Apocalipse 22:20: após a última promessa de Cristo ('Certamente venho em breve'), a resposta da Igreja é 'Amém, vem, Senhor Jesus!' — a mais breve e profunda oração cristã.",reference:"Apocalipse 22:20",category:.geral,propheticMeaning:"A Bíblia começa com Deus falando ('No princípio Deus') e termina com a Igreja respondendo ('Vem, Senhor Jesus') — a história bíblica é uma conversa entre Deus e seu povo que terminará em reunião eterna face a face."),
QuizQuestion(id:526,question:"O que Hebreus 1:1-2 diz sobre a revelação de Deus?",options:["Deus revelou-se apenas pelo AT","'Havendo Deus antigamente falado pelos profetas... agora nestes","Deus ainda fala apenas por profetas","Deus revelou-se apenas por sonhos"],correctIndex:1,explanation:"Hb 1:1-2: a revelação progressiva culmina em Cristo — os profetas deram revelação parcial e preparatória; o Filho é a revelação plena, final e pessoal de Deus.",reference:"Hebreus 1:1-2",category:.geral,propheticMeaning:"Cristo como Filho sendo a revelação definitiva supera toda revelação anterior — não porque o AT seja errado mas porque foi cumprido. Jesus é a exegese viva de Deus: 'quem me viu, viu o Pai' (Jo 14:9)."),
QuizQuestion(id:527,question:"O que Paulo ensina sobre a providência de Deus na própria vida em Gálatas 1:15-16?",options:["Que sua conversão foi acidental","'Aquele que me separou desde o ventre de minha mãe e me chamou pela...","Que ele mesmo escolheu servir a Cristo","Que Deus o chamou apenas após a conversão"],correctIndex:1,explanation:"Gálatas 1:15-16: Paulo reconhece que foi separado (eleito) desde o ventre materno pela graça de Deus — ecoando Jeremias 1:5 e Isaiah 49:1.",reference:"Gálatas 1:15-16",category:.geral,propheticMeaning:"Paulo reconhecendo providência desde o ventre materno é modelo da perspectiva cristã sobre a própria vida — cada crente foi 'preparado de antemão para as boas obras' (Ef 2:10) desde antes do nascimento."),
QuizQuestion(id:528,question:"O que Paulo ensina sobre a autoridade das Escrituras em 2 Timóteo 3:16-17?",options:["A Bíblia é útil mas não divina","'Toda a Escritura é inspirada por Deus e útil para ensinar","A Bíblia tem erros históricos","Apenas o NT é inspirado"],correctIndex:1,explanation:"2 Tm 3:16-17: 'toda a Escritura' é theopneustos (inspirada por Deus/soprada por Deus) — autoritativa em doutrina, prática, correção e instrução.",reference:"2 Timóteo 3:16-17",category:.geral,propheticMeaning:"'Soprada por Deus' não é ditação mecânica mas inspiração orgânica: o Espírito agiu através das personalidades e culturas dos autores para produzir exatamente a Palavra que Deus queria comunicar."),
QuizQuestion(id:529,question:"Qual é a promessa de João 16:33?",options:["'Pedi e recebereis'","'No mundo tereis aflições; mas tende ânimo, eu venci o mundo'","'Permanecei em mim'","'Sou o caminho, a verdade e a vida'"],correctIndex:1,explanation:"João 16:33: Jesus promete paz em si mesmo mesmo nas tribulações do mundo — baseada não nas circunstâncias mas em sua vitória já obtida.",reference:"João 16:33",category:.geral,propheticMeaning:"'Eu venci o mundo' (nikēka, perfeito grego = vitória completada com efeito contínuo) — Cristo venceu definitivamente; crentes participam de uma vitória já conquistada, não buscam uma vitória ainda incerta."),
QuizQuestion(id:530,question:"O que Paulo ensina sobre perseverança em 2 Timóteo 4:7-8?",options:["O cristão pode desistir","'Combati o bom combate, acabei a carreira","A perseverança é opcional","Apenas os apóstolos perseverarão"],correctIndex:1,explanation:"2 Tm 4:7-8: o legado de Paulo — bom combate, carreira concluída, fé preservada — e a certeza da coroa prometida ao amante da vinda de Cristo.",reference:"2 Timóteo 4:7-8",category:.geral,propheticMeaning:"'Doravante está-me guardada' (apokeitai — reservada, depositada com segurança) — a recompensa do crente fiel está não nas obras mas na promessa do Juiz justo que não falha."),
]
